solution:
"""Challenge 32 — Constructor injection with Protocols, no framework."""

from typing import Any, Protocol


# ---- the contracts (what SignupService actually needs) -------------------
class Sender(Protocol):
    def send(self, to: str, subject: str, body: str) -> None: ...


class Database(Protocol):
    def insert(self, table: str, row: dict[str, Any]) -> None: ...

    def exists(self, table: str, key: str, value: Any) -> bool: ...


# ---- the service: depends on protocols, constructs NOTHING ---------------
class SignupService:
    def __init__(self, sender: Sender, db: Database) -> None:
        self._sender = sender
        self._db = db

    def signup(self, email: str) -> bool:
        if self._db.exists("users", "email", email):
            return False
        self._db.insert("users", {"email": email})
        self._sender.send(email, "Welcome!", "Thanks for signing up.")
        return True


# ---- prod implementations (would live in adapters/) ----------------------
class SmtpClient:
    def __init__(self, host: str) -> None:
        self.host = host

    def send_message(self, to: str, subject: str, body: str) -> None:
        print(f"[smtp {self.host}] -> {to}: {subject}")


class EmailSender:
    def __init__(self, smtp: SmtpClient) -> None:  # injected, not built
        self._smtp = smtp

    def send(self, to: str, subject: str, body: str) -> None:
        self._smtp.send_message(to, subject, body)


class PostgresDb:
    def __init__(self, dsn: str) -> None:
        self.dsn = dsn
        self._rows: dict[str, list[dict[str, Any]]] = {}  # stand-in

    def insert(self, table: str, row: dict[str, Any]) -> None:
        self._rows.setdefault(table, []).append(row)

    def exists(self, table: str, key: str, value: Any) -> bool:
        return any(r.get(key) == value for r in self._rows.get(table, []))


# ---- composition root: the ONE place that knows concrete types -----------
def build_app(config: dict[str, str]) -> SignupService:
    smtp = SmtpClient(host=config["smtp_host"])
    sender = EmailSender(smtp)
    db = PostgresDb(config["db_dsn"])
    return SignupService(sender=sender, db=db)


# ---- test fakes: satisfy the Protocols by shape, import no prod code ------
class FakeSender:
    def __init__(self) -> None:
        self.sent: list[tuple[str, str]] = []

    def send(self, to: str, subject: str, body: str) -> None:
        self.sent.append((to, subject))


class InMemoryDb:
    def __init__(self) -> None:
        self.rows: list[dict[str, Any]] = []

    def insert(self, table: str, row: dict[str, Any]) -> None:
        self.rows.append(row)

    def exists(self, table: str, key: str, value: Any) -> bool:
        return any(r.get(key) == value for r in self.rows)


def test_signup_sends_welcome_and_dedupes() -> None:
    sender, db = FakeSender(), InMemoryDb()
    service = SignupService(sender=sender, db=db)  # wire fakes, no mocks lib

    assert service.signup("ada@example.com") is True
    assert service.signup("ada@example.com") is False  # duplicate blocked

    assert db.rows == [{"email": "ada@example.com"}]
    assert sender.sent == [("ada@example.com", "Welcome!")]


if __name__ == "__main__":
    app = build_app({"smtp_host": "prod-smtp", "db_dsn": "prod-dsn"})
    assert app.signup("first@example.com") is True

    test_signup_sends_welcome_and_dedupes()
    print("ok")

"""Challenge 34 — Three fixes for a circular import, materialized and tested.

Each fix is written as real module source, dumped into its own temp
directory, imported, and exercised — proving all three actually break the
cycle rather than just claiming to.

RANKING FOR A GROWING CODEBASE (best -> last resort):
  1) TYPE_CHECKING + deferred annotations  — when the cycle is TYPE-ONLY
     (as here: each module needs the other purely for hints). Zero runtime
     coupling, zero restructuring, standard idiom every reader knows.
  2) Restructure into a shared module      — when there is REAL runtime
     mutual dependency. The cycle is a design smell: two things that need
     each other at runtime are one cohesive cluster — move them together
     (models.py) or extract the shared core. Scales best long-term, but
     costs a refactor and can grow a "dumping ground" module if abused.
  3) Deferred (in-function) import         — a targeted patch. Works, but
     hides the dependency from readers and tools, moves ImportError to
     call time, and every deferred import is a landmine for the next
     refactor. Use to firefight, then schedule fix 1 or 2.
CHOICE: for hint-only cycles (the common case) -> fix 1; the moment the
dependency is behavioral -> fix 2. Fix 3 only as a stopgap.
"""

import importlib
import sys
from pathlib import Path
from textwrap import dedent

FIXES: dict[str, dict[str, str]] = {
    # ---- Fix 1: TYPE_CHECKING guard + string/deferred annotations -------
    "fix1_type_checking": {
        "order.py": dedent("""
            from __future__ import annotations
            from typing import TYPE_CHECKING

            if TYPE_CHECKING:                 # never executed at runtime
                from customer import Customer

            class Order:
                def __init__(self, customer: Customer, total: float) -> None:
                    self.customer = customer  # annotation is lazy -> no import needed
                    self.total = total
        """),
        "customer.py": dedent("""
            from __future__ import annotations
            from typing import TYPE_CHECKING

            if TYPE_CHECKING:
                from order import Order

            class Customer:
                def __init__(self, name: str) -> None:
                    self.name = name
                    self._orders: list[Order] = []

                def add_order(self, order: Order) -> None:
                    self._orders.append(order)

                def orders(self) -> list[Order]:
                    return list(self._orders)
        """),
    },
    # ---- Fix 2: restructure — both classes live in one cohesive module --
    "fix2_shared_module": {
        "models.py": dedent("""
            from __future__ import annotations

            class Customer:
                def __init__(self, name: str) -> None:
                    self.name = name
                    self._orders: list[Order] = []

                def add_order(self, order: Order) -> None:
                    self._orders.append(order)

                def orders(self) -> list[Order]:
                    return list(self._orders)

            class Order:
                def __init__(self, customer: Customer, total: float) -> None:
                    self.customer = customer
                    self.total = total
        """),
        # Thin re-export shims keep old import paths alive during migration:
        "order.py": "from models import Order\n",
        "customer.py": "from models import Customer\n",
    },
    # ---- Fix 3: deferred import inside the method ------------------------
    "fix3_deferred_import": {
        "order.py": dedent("""
            class Order:
                def __init__(self, customer, total: float) -> None:
                    self.customer = customer
                    self.total = total
        """),
        "customer.py": dedent("""
            class Customer:
                def __init__(self, name: str) -> None:
                    self.name = name
                    self._orders = []

                def add_order(self, order) -> None:
                    from order import Order   # deferred: runs at CALL time,
                    if not isinstance(order, Order):   # cycle already resolved
                        raise TypeError("expected an Order")
                    self._orders.append(order)

                def orders(self):
                    return list(self._orders)
        """),
    },
}


def try_fix(name: str, files: dict[str, str], base: Path) -> None:
    """Materialize one fix into its own dir, import it, exercise it."""
    fix_dir = base / name
    fix_dir.mkdir()
    for filename, source in files.items():
        (fix_dir / filename).write_text(source, encoding="utf-8")

    sys.path.insert(0, str(fix_dir))
    # Drop any modules a previous fix left behind so imports are fresh.
    for mod in ("order", "customer", "models"):
        sys.modules.pop(mod, None)
    try:
        customer_mod = importlib.import_module("customer")
        order_mod = importlib.import_module("order")

        ada = customer_mod.Customer("ada")
        order = order_mod.Order(ada, 99.5)
        ada.add_order(order)
        assert ada.orders()[0].total == 99.5
        assert order.customer.name == "ada"
        print(f"{name}: imports cleanly, round-trip works")
    finally:
        sys.path.remove(str(fix_dir))
        for mod in ("order", "customer", "models"):
            sys.modules.pop(mod, None)


if __name__ == "__main__":
    import tempfile

    with tempfile.TemporaryDirectory() as tmp:
        for fix_name, fix_files in FIXES.items():
            try_fix(fix_name, fix_files, Path(tmp))
    print("ok")

"""Challenge 36 — Tokenizer + recursive descent, then AST + match.

Grammar:  expr   := term (("+"|"-") term)*
          term   := factor (("*"|"/") factor)*
          factor := NUMBER | "(" expr ")"
"""

import re
from dataclasses import dataclass

# ---- lexer ----------------------------------------------------------------
_TOKEN_RE = re.compile(r"\s*(?:(\d+\.?\d*)|([+\-*/()]))")


def tokenize(src: str) -> list[str]:
    tokens: list[str] = []
    pos = 0
    while pos < len(src):
        m = _TOKEN_RE.match(src, pos)
        if m is None:
            raise SyntaxError(f"unexpected character {src[pos]!r} at {pos}")
        tokens.append(m.group(1) or m.group(2))
        pos = m.end()
    return tokens


# ---- version 1: direct recursive-descent evaluation ------------------------
class _Parser:
    """One method per grammar rule; precedence comes from the call
    structure itself: expr calls term calls factor, so * / bind tighter."""

    def __init__(self, tokens: list[str]) -> None:
        self.tokens = tokens
        self.pos = 0

    def peek(self) -> str | None:
        return self.tokens[self.pos] if self.pos < len(self.tokens) else None

    def take(self) -> str:
        token = self.peek()
        if token is None:
            raise SyntaxError("unexpected end of input")
        self.pos += 1
        return token

    def expr(self) -> float:
        value = self.term()
        while self.peek() in ("+", "-"):
            if self.take() == "+":
                value += self.term()
            else:
                value -= self.term()
        return value

    def term(self) -> float:
        value = self.factor()
        while self.peek() in ("*", "/"):
            if self.take() == "*":
                value *= self.factor()
            else:
                value /= self.factor()
        return value

    def factor(self) -> float:
        token = self.take()
        if token == "(":
            value = self.expr()
            if self.take() != ")":
                raise SyntaxError("expected ')'")
            return value
        try:
            return float(token)
        except ValueError:
            raise SyntaxError(f"expected a number, got {token!r}") from None


def evaluate(tokens: list[str]) -> float:
    parser = _Parser(tokens)
    result = parser.expr()
    if parser.peek() is not None:
        raise SyntaxError(f"trailing input from {parser.peek()!r}")
    return result


# ---- version 2: parse to an AST, then evaluate with match -------------------
@dataclass(frozen=True)
class Num:
    value: float


@dataclass(frozen=True)
class BinOp:
    op: str
    left: "Expr"
    right: "Expr"


type Expr = Num | BinOp


class _AstParser(_Parser):
    """Same grammar walk, but each rule BUILDS a node instead of computing.
    Only the 'what to do at each step' changes — that's the layering."""

    def expr(self) -> Expr:  # type: ignore[override]
        node = self.term()
        while self.peek() in ("+", "-"):
            node = BinOp(self.take(), node, self.term())
        return node

    def term(self) -> Expr:  # type: ignore[override]
        node = self.factor()
        while self.peek() in ("*", "/"):
            node = BinOp(self.take(), node, self.factor())
        return node

    def factor(self) -> Expr:  # type: ignore[override]
        token = self.take()
        if token == "(":
            node = self.expr()
            if self.take() != ")":
                raise SyntaxError("expected ')'")
            return node
        try:
            return Num(float(token))
        except ValueError:
            raise SyntaxError(f"expected a number, got {token!r}") from None


def parse(tokens: list[str]) -> Expr:
    parser = _AstParser(tokens)
    tree = parser.expr()
    if parser.peek() is not None:
        raise SyntaxError(f"trailing input from {parser.peek()!r}")
    return tree


def eval_ast(node: Expr) -> float:
    match node:
        case Num(value):
            return value
        case BinOp("+", left, right):
            return eval_ast(left) + eval_ast(right)
        case BinOp("-", left, right):
            return eval_ast(left) - eval_ast(right)
        case BinOp("*", left, right):
            return eval_ast(left) * eval_ast(right)
        case BinOp("/", left, right):
            return eval_ast(left) / eval_ast(right)
        case _:
            raise TypeError(f"unknown node: {node!r}")


def evaluate_via_ast(tokens: list[str]) -> float:
    return eval_ast(parse(tokens))


if __name__ == "__main__":
    cases = {
        "1 + 2 * 3": 7.0,                 # precedence
        "(1 + 2) * 3": 9.0,               # parentheses
        "10 - 4 - 3": 3.0,                # left associativity
        "8 / 4 / 2": 1.0,
        "2 * (3 + 4) - 5 / (1 + 1)": 11.5,
        "42": 42.0,
        "3.5 * 2": 7.0,
    }
    for src, expected in cases.items():
        tokens = tokenize(src)
        assert evaluate(tokens) == expected, (src, evaluate(tokens))
        assert evaluate_via_ast(tokens) == expected
        print(f"{src:28s} = {expected}")

    # The AST itself is inspectable — the payoff of the two-layer design.
    tree = parse(tokenize("1 + 2 * 3"))
    assert tree == BinOp("+", Num(1.0), BinOp("*", Num(2.0), Num(3.0)))

    for bad in ["1 +", "(1 + 2", "1 $ 2", "1 2"]:
        try:
            evaluate_via_ast(tokenize(bad))
        except SyntaxError as exc:
            print(f"rejected {bad!r}: {exc}")
    print("ok")

"""Challenge 37 — __init_subclass__ registry with definition-time checks."""

import json
from typing import Any, ClassVar


class Serializer:
    """Subclasses must declare `format: str` and implement dumps().
    They auto-register into Serializer.registry keyed by format.
    Duplicate formats or missing attributes fail AT CLASS DEFINITION
    TIME. Intermediate bases pass abstract=True to skip registration."""

    registry: ClassVar[dict[str, type["Serializer"]]] = {}

    def __init_subclass__(cls, *, abstract: bool = False, **kwargs: Any) -> None:
        # Always cooperate with other bases in the MRO.
        super().__init_subclass__(**kwargs)

        if abstract:
            return  # intermediate base: no contract check, no registration

        # `format` must be declared (inheriting one from an abstract
        # intermediate is fine — hence getattr, not cls.__dict__).
        fmt = getattr(cls, "format", None)
        if fmt is None:
            raise TypeError(
                f"{cls.__name__} must declare a class attribute `format: str`"
            )
        if not isinstance(fmt, str):
            raise TypeError(
                f"{cls.__name__}.format must be str, "
                f"got {type(fmt).__name__} ({fmt!r})"
            )

        dumps = getattr(cls, "dumps", None)
        if dumps is None or dumps is Serializer.dumps:
            raise TypeError(f"{cls.__name__} must implement dumps(self, data)")

        if fmt in Serializer.registry:
            other = Serializer.registry[fmt].__name__
            raise TypeError(
                f"duplicate serializer format {fmt!r}: "
                f"{cls.__name__} clashes with {other}"
            )

        Serializer.registry[fmt] = cls

    def dumps(self, data: Any) -> str:  # contract anchor for the check above
        raise NotImplementedError

    @classmethod
    def for_format(cls, fmt: str) -> "Serializer":
        try:
            return cls.registry[fmt]()
        except KeyError:
            known = ", ".join(sorted(cls.registry)) or "<none>"
            raise ValueError(f"no serializer for {fmt!r}; known: {known}") from None


class JsonSerializer(Serializer):
    format = "json"

    def dumps(self, data: Any) -> str:
        return json.dumps(data, sort_keys=True)


class TextSerializer(Serializer, abstract=True):
    """Intermediate base: adds a helper, is NOT registered itself."""

    separator = "\n"

    def join(self, parts: list[str]) -> str:
        return self.separator.join(parts)


class KeyValueSerializer(TextSerializer):
    format = "kv"

    def dumps(self, data: Any) -> str:
        return self.join(f"{k}={v}" for k, v in dict(data).items())  # type: ignore[arg-type]


if __name__ == "__main__":
    assert sorted(Serializer.registry) == ["json", "kv"]
    assert "TextSerializer" not in {c.__name__ for c in Serializer.registry.values()}

    assert Serializer.for_format("json").dumps({"b": 1, "a": 2}) == '{"a": 2, "b": 1}'
    assert Serializer.for_format("kv").dumps({"x": 1}) == "x=1"

    # Every violation fails AT CLASS DEFINITION TIME:
    for description, definition in {
        "missing format": lambda: type(
            "NoFormat", (Serializer,), {"dumps": lambda self, d: ""}
        ),
        "non-str format": lambda: type(
            "BadFormat", (Serializer,), {"format": 42, "dumps": lambda self, d: ""}
        ),
        "missing dumps": lambda: type(
            "NoDumps", (Serializer,), {"format": "yaml"}
        ),
        "duplicate format": lambda: type(
            "JsonAgain", (Serializer,), {"format": "json", "dumps": lambda self, d: ""}
        ),
    }.items():
        try:
            definition()
        except TypeError as exc:
            print(f"{description:18s} -> TypeError: {exc}")
        else:
            raise AssertionError(f"{description} was not caught")
    print("ok")

"""Challenge 38 — A real metaclass: enforce, wrap, and inject."""

import functools
import re
import time
from collections.abc import Callable
from typing import Any


def _snake_case(name: str) -> str:
    """PaymentService -> payment_service, HTTPService -> http_service."""
    step1 = re.sub(r"(.)([A-Z][a-z]+)", r"\1_\2", name)
    return re.sub(r"([a-z0-9])([A-Z])", r"\1_\2", step1).lower()


def _timed(fn: Callable[..., Any]) -> Callable[..., Any]:
    @functools.wraps(fn)
    def wrapper(*args: Any, **kwargs: Any) -> Any:
        start = time.perf_counter()
        try:
            return fn(*args, **kwargs)
        finally:
            elapsed = (time.perf_counter() - start) * 1000
            print(f"[timing] {fn.__qualname__} took {elapsed:.3f} ms")

    return wrapper


class ServiceMeta(type):
    """1) Every concrete class must define `handle(self, request)`.
       2) Every method whose name starts with `handle` gets wrapped
          to log call duration.
       3) Classes get an auto-generated `service_name` = snake_case
          of the class name.

    WHICH FEATURES ACTUALLY NEED A METACLASS?
    (1) and (3) could be done with __init_subclass__ on a base class, and
    all three with a class decorator — wrapping methods (2) too, since a
    decorator sees the finished class and can setattr replacements.
    What the metaclass uniquely buys:
      * It rewrites the NAMESPACE BEFORE the type object exists, so the
        class is never observable in its unwrapped state (decorators
        mutate after creation; __init_subclass__ can't replace the
        namespace at all — and doesn't run for the base class itself).
      * It is INESCAPABLE and INHERITED: every subclass anywhere gets the
        treatment without remembering a decorator or inheriting a
        specific base — `type(cls)` IS the guarantee.
      * Only a metaclass can change what `class` produces (isinstance of
        the class object itself, __call__ interception, etc.).
    Rule of thumb: prefer decorator < __init_subclass__ < metaclass;
    reach for the metaclass when the guarantee must be unforgeable.
    """

    def __new__(
        mcls,
        name: str,
        bases: tuple[type, ...],
        namespace: dict[str, Any],
        **kwargs: Any,
    ) -> type:
        abstract = kwargs.pop("abstract", False)

        # (1) Enforce the interface on concrete classes (own or inherited).
        if not abstract:
            has_handle = "handle" in namespace or any(
                hasattr(base, "handle") for base in bases
            )
            if not has_handle:
                raise TypeError(
                    f"{name} must define handle(self, request) "
                    f"(or inherit it); mark intermediate bases abstract=True"
                )

        # (2) Wrap every handle* method defined in THIS class body.
        for attr, value in namespace.items():
            if attr.startswith("handle") and callable(value):
                namespace[attr] = _timed(value)

        # (3) Inject the derived service_name (overridable by declaring one).
        namespace.setdefault("service_name", _snake_case(name))

        return super().__new__(mcls, name, bases, namespace, **kwargs)


class ServiceBase(metaclass=ServiceMeta, abstract=True):
    """Optional convenience base so users write class X(ServiceBase)."""


class PaymentService(ServiceBase):
    def handle(self, request: dict) -> str:
        time.sleep(0.01)
        return f"charged {request['amount']}"

    def handle_refund(self, request: dict) -> str:
        return f"refunded {request['amount']}"

    def helper(self) -> str:  # not handle* -> not wrapped
        return "no timing for me"


class HTTPGatewayService(ServiceBase):
    def handle(self, request: dict) -> str:
        return "routed"


if __name__ == "__main__":
    svc = PaymentService()

    assert PaymentService.service_name == "payment_service"
    assert HTTPGatewayService.service_name == "http_gateway_service"

    assert svc.handle({"amount": 42}) == "charged 42"      # prints timing
    assert svc.handle_refund({"amount": 7}) == "refunded 7"  # prints timing
    assert svc.helper() == "no timing for me"              # silent

    try:
        class BrokenService(ServiceBase):  # no handle -> definition-time error
            pass
    except TypeError as exc:
        print(f"enforced: {exc}")

    # The metaclass guarantee: every service IS an instance of ServiceMeta.
    assert isinstance(PaymentService, ServiceMeta)
    print("ok")

"""Challenge 39 — Mini ORM: descriptors for fields, metaclass for models."""

from typing import Any


class Field:
    """Data descriptor: validates type on every assignment."""

    def __init__(self, py_type: type, primary_key: bool = False) -> None:
        self.py_type = py_type
        self.primary_key = primary_key
        self.name = "<unbound>"

    def __set_name__(self, owner: type, name: str) -> None:
        self.name = name

    def __get__(self, obj: Any, objtype: type | None = None) -> Any:
        if obj is None:
            return self  # class access -> the Field itself (introspection)
        return obj.__dict__[self.name]

    def __set__(self, obj: Any, value: Any) -> None:
        # NB: isinstance, so bool sneaks into int fields (bool subclasses
        # int) — matching Python's own semantics; use `type(value) is`
        # for strictness if desired.
        if not isinstance(value, self.py_type):
            raise TypeError(
                f"{type(obj).__name__}.{self.name} expects "
                f"{self.py_type.__name__}, got {type(value).__name__} "
                f"({value!r})"
            )
        obj.__dict__[self.name] = value

    def __repr__(self) -> str:
        pk = ", primary_key=True" if self.primary_key else ""
        return f"Field({self.py_type.__name__}{pk})"


class ModelMeta(type):
    """Collect Field attributes into cls._fields (ordered), validate
    exactly one primary key, generate __init__ (kwargs, type-checked via
    the descriptors) and to_dict()."""

    def __new__(
        mcls, name: str, bases: tuple[type, ...], namespace: dict[str, Any]
    ) -> type:
        cls = super().__new__(mcls, name, bases, namespace)

        # Class bodies preserve definition order (dicts are ordered), so
        # _fields is ordered exactly as written in the class.
        fields = {
            attr: value
            for attr, value in namespace.items()
            if isinstance(value, Field)
        }
        cls._fields = fields

        if not fields:
            return cls  # a base/mixin without fields: leave it alone

        primary_keys = [n for n, f in fields.items() if f.primary_key]
        if len(primary_keys) != 1:
            raise TypeError(
                f"{name} must define exactly one primary key field, "
                f"found {len(primary_keys)}: {primary_keys or 'none'}"
            )
        cls._primary_key = primary_keys[0]

        def __init__(self: Any, **kwargs: Any) -> None:
            for field_name in type(self)._fields:
                if field_name not in kwargs:
                    raise TypeError(f"missing required field {field_name!r}")
                # setattr routes through Field.__set__ -> type check.
                setattr(self, field_name, kwargs.pop(field_name))
            if kwargs:
                raise TypeError(
                    f"unknown field(s) for {type(self).__name__}: "
                    f"{sorted(kwargs)}"
                )

        def to_dict(self: Any) -> dict[str, Any]:
            return {n: getattr(self, n) for n in type(self)._fields}

        def __repr__(self: Any) -> str:
            pairs = ", ".join(f"{n}={getattr(self, n)!r}" for n in type(self)._fields)
            return f"{type(self).__name__}({pairs})"

        cls.__init__ = __init__
        cls.to_dict = to_dict
        cls.__repr__ = __repr__
        return cls


class User(metaclass=ModelMeta):
    id = Field(int, primary_key=True)
    email = Field(str)


if __name__ == "__main__":
    user = User(id=1, email="a@b.c")
    assert user.id == 1 and user.email == "a@b.c"
    assert user.to_dict() == {"id": 1, "email": "a@b.c"}
    assert repr(user) == "User(id=1, email='a@b.c')"
    assert list(User._fields) == ["id", "email"]        # ordered
    assert User._primary_key == "id"
    assert isinstance(User.id, Field)                   # class access

    for bad_call in (
        lambda: User(id="x", email="a@b.c"),            # wrong type
        lambda: User(id=2),                             # missing field
        lambda: User(id=2, email="e", extra=True),      # unknown field
    ):
        try:
            bad_call()
        except TypeError as exc:
            print(f"rejected: {exc}")
        else:
            raise AssertionError("bad call was accepted")

    user.email = "new@b.c"                              # revalidated on set
    try:
        user.email = 123
    except TypeError as exc:
        print(f"rejected: {exc}")

    # Exactly-one-primary-key is enforced at class definition time.
    try:
        class NoPk(metaclass=ModelMeta):
            name = Field(str)
    except TypeError as exc:
        print(f"rejected: {exc}")

    try:
        class TwoPk(metaclass=ModelMeta):
            a = Field(int, primary_key=True)
            b = Field(int, primary_key=True)
    except TypeError as exc:
        print(f"rejected: {exc}")
    print("ok")
